// src/pages/Attendance/AttendanceReportsPage.js
import React, { useState, useEffect } from 'react';
import { attendanceAPI, employeeAPI } from '../../api/services';
import { SkeletonCard } from '../../components/common';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';

const COLORS = ['var(--green)','var(--red)','var(--amber)','var(--purple)','var(--blue)'];

export default function AttendanceReportsPage() {
  const [summary, setSummary] = useState(null);
  const [kpis,    setKpis]    = useState(null);
  const [loading, setLoading] = useState(true);
  const [empId,   setEmpId]   = useState('');
  const [employees, setEmployees] = useState([]);

  const unwrap = r => { const o = r?.data; return o && 'data' in o ? o.data : o; };

  useEffect(() => {
    Promise.all([
      attendanceAPI.getDashboardKPIs(),
      employeeAPI.list({ limit: 100 }),
    ]).then(([k, e]) => {
      setKpis(unwrap(k));
      const ep = unwrap(e);
      setEmployees(Array.isArray(ep) ? ep : ep?.employees || []);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const loadSummary = (id) => {
    if (!id) return;
    attendanceAPI.getSummary(id)
      .then(r => setSummary(unwrap(r)))
      .catch(() => {});
  };

  const summaryData = summary ? [
    { name: 'Present',  value: summary.PresentDays  || summary.presentDays  || 0 },
    { name: 'Absent',   value: summary.AbsentDays   || summary.absentDays   || 0 },
    { name: 'Leave',    value: summary.LeaveDays    || summary.leaveDays    || 0 },
    { name: 'Holiday',  value: summary.HolidayDays  || summary.holidayDays  || 0 },
  ].filter(d => d.value > 0) : [];

  const kpiCards = kpis ? [
    { label: 'Present Today',     value: kpis.presentToday    ?? kpis.PresentToday    ?? '—' },
    { label: 'Absent Today',      value: kpis.absentToday     ?? kpis.AbsentToday     ?? '—' },
    { label: 'Late Today',        value: kpis.lateToday       ?? kpis.LateToday       ?? '—' },
    { label: 'Avg Hours / Day',   value: kpis.avgHoursPerDay  ?? kpis.AvgHoursPerDay  ? `${kpis.avgHoursPerDay || kpis.AvgHoursPerDay}h` : '—' },
    { label: 'Attendance Rate',   value: kpis.attendanceRate  ?? kpis.AttendanceRate  ? `${kpis.attendanceRate || kpis.AttendanceRate}%` : '—' },
    { label: 'On Leave Today',    value: kpis.onLeaveToday    ?? kpis.OnLeaveToday    ?? '—' },
  ] : [];

  return (
    <>
      <div className="page-header">
        <h1>Reports & Analytics</h1>
        <p>Attendance overview and employee summaries</p>
      </div>

      {/* KPI Cards */}
      {loading ? (
        <div className="grid-4" style={{ marginBottom: 24 }}>
          {[1,2,3,4].map(i => <SkeletonCard key={i} />)}
        </div>
      ) : (
        <div className="grid-4" style={{ marginBottom: 24 }}>
          {kpiCards.map(({ label, value }) => (
            <div key={label} className="stat-card">
              <div className="stat-card-value" style={{ color: 'var(--gold)' }}>{value}</div>
              <div className="stat-card-label">{label}</div>
            </div>
          ))}
        </div>
      )}

      {/* Employee Summary */}
      <div className="card">
        <div className="card-header">
          <div className="card-title">Employee Monthly Summary</div>
          <select
            className="form-select"
            style={{ width: 240 }}
            value={empId}
            onChange={e => { setEmpId(e.target.value); loadSummary(e.target.value); }}
          >
            <option value="">Select an employee...</option>
            {employees.map(emp => (
              <option key={emp.EmployeeID || emp.id} value={emp.EmployeeID || emp.id}>
                {emp.FullName || emp.fullName || `${emp.FirstName} ${emp.LastName}`}
              </option>
            ))}
          </select>
        </div>

        {summary && summaryData.length > 0 ? (
          <div className="grid-2" style={{ marginTop: 16 }}>
            <div>
              <div style={{ fontWeight: 600, fontSize: '0.85rem', marginBottom: 12, color: 'var(--text-secondary)' }}>Day Distribution</div>
              <ResponsiveContainer width="100%" height={220}>
                <PieChart>
                  <Pie data={summaryData} cx="50%" cy="50%" outerRadius={80} dataKey="value" label={({ name, value }) => `${name}: ${value}`} labelLine={false}>
                    {summaryData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                  </Pie>
                  <Tooltip contentStyle={{ background: 'var(--bg-elevated)', border: '1px solid var(--border)', borderRadius: 8, fontSize: 12 }} />
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div>
              <div style={{ fontWeight: 600, fontSize: '0.85rem', marginBottom: 12, color: 'var(--text-secondary)' }}>Summary Details</div>
              {[
                { label: 'Working Days',     value: summary.TotalWorkingDays  || summary.totalWorkingDays  || '—' },
                { label: 'Present',          value: summary.PresentDays       || summary.presentDays       || '—' },
                { label: 'Absent',           value: summary.AbsentDays        || summary.absentDays        || '—' },
                { label: 'Total Hours',      value: summary.TotalWorkedHours  || summary.totalWorkedHours  ? `${summary.TotalWorkedHours || summary.totalWorkedHours}h` : '—' },
                { label: 'Overtime Hours',   value: summary.TotalOvertimeHrs  || summary.totalOvertimeHrs  ? `${summary.TotalOvertimeHrs || summary.totalOvertimeHrs}h` : '—' },
                { label: 'Late Minutes',     value: summary.TotalLatenessMins || summary.totalLatenessMins ? `${summary.TotalLatenessMins || summary.totalLatenessMins} min` : '—' },
                { label: 'On-Time Rate',     value: summary.OnTimeRate        || summary.onTimeRate        ? `${summary.OnTimeRate || summary.onTimeRate}%` : '—' },
              ].map(({ label, value }) => (
                <div className="info-row" key={label}>
                  <span className="info-row-label">{label}</span>
                  <span className="info-row-value">{value}</span>
                </div>
              ))}
            </div>
          </div>
        ) : empId ? (
          <div style={{ textAlign: 'center', padding: 40, color: 'var(--text-muted)' }}>No summary data available for this employee</div>
        ) : (
          <div style={{ textAlign: 'center', padding: 40, color: 'var(--text-muted)' }}>Select an employee to view their monthly summary</div>
        )}
      </div>
    </>
  );
}
